var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"아, 진짜! 됐으니까 헛소리 좀 그만해!","JPN":"もういいから、戯言はそれくらいにして！","ENG":"Argh, seriously? Enough with this crap!","TWN":"啊，夠了！別再瞎說了！"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그리고 음악 좀 꺼! 자칭 두뇌파 용병이라는 아저씨라도 나올 거 같잖아!","JPN":"それに、この音楽消せないの？　自称頭脳派傭兵のおじさんでも出てきそうじゃない！","ENG":"And turn off the music! It keeps reminding me of that \\"Intelligent Mercenary!\\"","TWN":"能不能關掉音樂！感覺會出現傭兵大叔！"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"성야의 살인마라니, 그거 그냥 겁 주려고 한 소리 아니었어?","JPN":"聖夜の殺人鬼って、ただアタシたちを怖がらせるための作り話じゃなかったの？","ENG":"The Killer of the Holy Night. I thought you just made it up to scare us.","TWN":"耶誕的嫌疑犯，那不就是為了唬人的嗎？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"확실히 그때는 분위기를 살리려고 얘기했네만, 이렇게 확실한 증거가 나왔는데 부정할 수는 없지.","JPN":"あの時は場を盛り上げようとした話だったが、現に確実な証拠が出た以上、否定はできないだろう。","ENG":"I only mentioned it to spice up the mood, but now that we have such firm proof, it's the undeniable truth.","TWN":"當時我確實是為了搞活氣氛才那麼說的，不過現在證據確鑿，就不能否定此人的存在了。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그것이 바로 21세기를 살아가는 현대인의 합리적인 자세가 아니겠나?","JPN":"それこそ21世紀を生きる現代人の合理的な姿勢ではないか？","ENG":"And I say accepting the truth is a rational approach to take, for someone living in the twenty-first century.","TWN":"作為活在21世紀的現代人，就應該持這般合理的態度不是嗎？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이야기 속 장본인인지, 이야기를 모방하려는 모방범인지는 모르겠지만 말일세.","JPN":"その伝説の張本人か、模倣犯なのかはわからないがな。","ENG":"Although it's yet to be known if this perpetrator is the original Killer or a copycat.","TWN":"雖然我不知道他是故事中的本人，還是想模仿殺人魔的人。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"그, 그럼 이 병사의 운명은 어떻게 되는 거지?","JPN":"そ、それじゃあ、この兵士の運命はどうなるのだ？","ENG":"Th-then, what's going to become of this soldier now?","TWN":"那、那這個士兵會怎麼樣？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"설마 이대로 영영 깨어나지 못하는 건가?","JPN":"まさか、このまま永遠に目を覚まさないなんてことは。","ENG":"Will he be stuck in this state forever?","TWN":"不會就這樣永遠醒不了吧？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"전설에 따르면......","JPN":"伝説によると……","ENG":"According to legend...","TWN":"根據傳說……"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"사냥감의 낙인이 찍힌 자는 영원히 깨어나지 못한 채 어둠 속을 헤맨다고 하지.","JPN":"獲物の烙印が押された者は、永遠に目を覚まさないまま闇の中を彷徨うという。","ENG":"those marked by him will be forever cursed to roam in the darkness.","TWN":"有獵物印記的人會永遠沉睡下去並遊蕩於黑暗中。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"......!!","JPN":"……！？","ENG":"......!!","TWN":"……！！"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"무, 무시무시한 녀석이군. 성야의 살인마.","JPN":"お、恐ろしい奴だ。聖夜の殺人鬼。","ENG":"H-he's a scary one, that Killer of the Holy Night.","TWN":"耶、耶誕的嫌疑犯，真是可怕的傢伙。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"하지만 본관에게는 스미스 병장이 있으니 두렵지 않아.","JPN":"しかし、本官にはスミス兵長がいるから怖くはない。","ENG":"But I've got my Sergeant Smith. I'm not afraid.","TWN":"但本官有史密斯兵長，所以我不怕。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"저, 전장에 몸을 던진 자로서...... 언젠가 이런 날이 올 줄은 알고 있었다......!","JPN":"せ、戦場に身を投じた者として……いつかこんな日が来ると思っていたのだ……！","ENG":"A-as a full-fledged soldier, I knew this day was coming.","TWN":"作、作為馳騁沙場的人……我知道總有這一天的到來……！"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"그저 하림 대장에게 마지막 인사를 전하지 못한 것이 아쉬울 뿐......","JPN":"ただウサギ隊長に最後の挨拶ができなかったのが、心残りなだけだ……","ENG":"I only regret that I don't get to say goodbye to Captain Harim one last time...","TWN":"可惜的是，沒能給夏琳隊長做最後的道別……"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SMITH_TOY_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"사, 사실 무서워요! 하림 언니, 호진 언니 도와줘어어어!! 흐에엥!!","JPN":"ほ、本当は怖いです！　ウサギお姉ちゃん、マユミお姉ちゃん、助けてぇ！　うわ～ん！","ENG":"F-forget it—I'm scared! Harim! Hojin! Help! Boohoo!","TWN":"我、我其實很害怕！夏琳姐姐，鎬眞姐姐，快來幫我啊啊啊！！嗚嗚嗚！！"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"자, 자. 이리 와, 우리 늠름한 꼬마 군인님.","JPN":"さぁ、さぁ、こっちに来なさい。勇敢なおチビの軍人さん。","ENG":"Aww. Come over here, little soldier.","TWN":"來、來這裡，我們英勇的小軍人。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};